    if ("SANDBOX".equalsIgnoreCase(env))
        return SANDBOX;
    else if ("ALLOWLIST".equalsIgnoreCase(env))
        return ALLOWLIST;
    else if ("INTERNET".equalsIgnoreCase(env))
        return INTERNET;
    else if ("UNSECURE".equalsIgnoreCase(env))
        return UNSECURE;
    return LEGACY;  // <-- DEFAULT, no SSRF protection
}

private boolean forbiddenURL(String full) {
    if (full.startsWith("https://") == false && full.startsWith("http://") == false)
        return true;
    if (full.matches("^https?://[-#.0-9:\\[\\]+]+/.*"))
        return true;
    if (full.matches("^https?://[^.]+/.*"))
        return true;
    if (full.matches("^https?://[^.]+$"))
        return true;
    return false;
}

